import re
import numpy as np
import matplotlib.pyplot as plt
from matplotlib.colors import LogNorm
import glob
import os

# plots the heatmaps generated by xB_Q2_scan.cpp

def parse_int(pattern: str, text: str, default: int) -> int:
    m = re.search(pattern, text)
    return int(m.group(1)) if m else default


def parse_float(pattern: str, text: str, default: float) -> float:
    m = re.search(pattern, text)
    return float(m.group(1)) if m else default


def discover_xb_q2_files():
    """Discover all available xB-Q2 histogram files"""
    # Check for organized directory structure first
    script_dir = os.path.dirname(os.path.abspath(__file__))
    # Explicitly add analysis_output/txt_files relative to script_dir
    analysis_txt_dir = os.path.join(script_dir, '..', 'analysis_output', 'txt_files')
    # Also check parent directory (workspace root) for analysis_output/txt_files
    parent_dir = os.path.abspath(os.path.join(script_dir, '..', '..', '..', '..'))
    parent_analysis_txt_dir = os.path.join(parent_dir, 'analysis_output', 'txt_files')
    txt_dir_candidates = [
        analysis_txt_dir,
        parent_analysis_txt_dir,
        script_dir,
        parent_dir
    ]
    print("Searching for input files in these directories:")
    for d in txt_dir_candidates:
        print("  ", d)

    found_files = {'pair': [], 'region': [], 'point': []}
    for d in txt_dir_candidates:
        if os.path.exists(d):
            found_files['pair'] += [os.path.join(d, "hist_xB_Q2_pair1.txt"), os.path.join(d, "hist_xB_Q2_pair2.txt")]
            found_files['region'] += glob.glob(os.path.join(d, "hist_xB_Q2_region*.txt"))
            found_files['point'] += glob.glob(os.path.join(d, "hist_xB_Q2_point*.txt"))

    # Remove duplicates and non-existent files
    found_files['pair'] = [f for f in dict.fromkeys(found_files['pair']) if os.path.exists(f)]
    found_files['region'] = [f for f in dict.fromkeys(found_files['region']) if os.path.exists(f)]
    found_files['point'] = [f for f in dict.fromkeys(found_files['point']) if os.path.exists(f)]
    # Sort region files by region number
    found_files['region'] = sorted(found_files['region'], key=lambda x: int(re.search(r'region(\d+)', x).group(1)) if re.search(r'region(\d+)', x) else 0)
    # Sort point files by point number
    found_files['point'] = sorted(found_files['point'], key=lambda x: int(re.search(r'point(\d+)', x).group(1)) if re.search(r'point(\d+)', x) else 0)

    print("Found files:")
    for k in found_files:
        for f in found_files[k]:
            print(f"  {k}: {f}")
    if not any(found_files.values()):
        print("ERROR: No xB-Q2 histogram files found in analysis_output/txt_files or script directory.")
    return found_files['pair'], found_files['region'], found_files['point']


def get_point_label(path: str) -> str:
    """Extract a meaningful label from the file path"""
    if "pair1" in path:
        return "Star (Pair 1)"
    elif "pair2" in path:
        return "Rocket (Pair 2)"
    elif "region" in path:
        # Extract region number
        match = re.search(r'region(\d+)', path)
        if match:
            region_num = int(match.group(1))
            return f"Region {region_num}"
    elif "point" in path:
        # Extract point number
        match = re.search(r'point(\d+)', path)
        if match:
            point_num = int(match.group(1))
            return f"Point {point_num}"
    return "Unknown"


def extract_target_angles(target_info: str) -> tuple:
    """Extract theta12 and theta23 values from target info string"""
    theta12_match = re.search(r'theta12=([\d.]+)', target_info)
    theta23_match = re.search(r'theta23=([\d.]+)', target_info)
    if theta12_match and theta23_match:
        return float(theta12_match.group(1)), float(theta23_match.group(1))
    return None, None


def get_enhanced_label(path: str, target_info: str) -> str:
    """Get an enhanced label including target angles"""
    base_label = get_point_label(path)
    theta12, theta23 = extract_target_angles(target_info)
    
    if theta12 is not None and theta23 is not None:
        # Special names for known configurations
        if abs(theta12 - 120.0) < 1.0 and abs(theta23 - 120.0) < 1.0:
            return f"Star (θ₁₂={theta12:.0f}°, θ₂₃={theta23:.0f}°)"
        elif abs(theta12 - 180.0) < 1.0 and abs(theta23 - 0.0) < 1.0:
            return f"Rocket (θ₁₂={theta12:.0f}°, θ₂₃={theta23:.0f}°)"
        elif abs(theta12 - 0.0) < 1.0 and abs(theta23 - 180.0) < 1.0:
            return f"(θ₁₂={theta12:.0f}°, θ₂₃={theta23:.0f}°)"
        elif abs(theta12 - 180.0) < 1.0 and abs(theta23 - 180.0) < 1.0:
            return f"(θ₁₂={theta12:.0f}°, θ₂₃={theta23:.0f}°)"
        else:
            return f"{base_label} (θ₁₂={theta12:.0f}°, θ₂₃={theta23:.0f}°)"
    
    return base_label


def load_xb_q2_hist(path: str):
    """Load sparse xB-Q2 histogram from hist_xB_Q2.txt.
    Returns xB centers, Q2 centers, a dense heatmap grid of shape [Q2_index, xB_index],
    and target angle information if available.
    """
    # Read header
    header = ""
    target_info = ""
    with open(path, "r") as f:
        for line in f:
            if line.startswith("#"):
                header += line
                if "Target pair" in line or "point" in line or "region" in line:
                    target_info = line.strip()
            else:
                break

    xB_bins = parse_int(r"xB_bins\s+(\d+)", header, 0)
    Q2_bins = parse_int(r"Q2_bins\s+(\d+)", header, 0)
    xB_min = parse_float(r"xB_min\s+([-+]?\d*\.?\d+(?:[eE][-+]?\d+)?)", header, 0.0)
    xB_max = parse_float(r"xB_max\s+([-+]?\d*\.?\d+(?:[eE][-+]?\d+)?)", header, 0.0)
    Q2_min = parse_float(r"Q2_min\s+([-+]?\d*\.?\d+(?:[eE][-+]?\d+)?)", header, 0.0)
    Q2_max = parse_float(r"Q2_max\s+([-+]?\d*\.?\d+(?:[eE][-+]?\d+)?)", header, 0.0)

    if xB_bins <= 0 or Q2_bins <= 0:
        raise ValueError("Could not parse xB_bins/Q2_bins from header of " + path)

    # Bin widths and centers
    dxB = (xB_max - xB_min) / xB_bins
    dQ2 = (Q2_max - Q2_min) / Q2_bins
    xb_centers = np.linspace(xB_min + dxB / 2.0, xB_max - dxB / 2.0, xB_bins)
    q2_centers = np.linspace(Q2_min + dQ2 / 2.0, Q2_max - dQ2 / 2.0, Q2_bins)

    # Prepare full grid (y: Q2, x: xB)
    heatmap = np.zeros((Q2_bins, xB_bins), dtype=float)

    # Load numeric rows, ignoring comments
    data = np.loadtxt(path, comments="#")
    if data.ndim == 1 and data.size == 0:
        return xb_centers, q2_centers, heatmap, (xB_min, xB_max, Q2_min, Q2_max), target_info

    data = np.atleast_2d(data)
    xb = data[:, 0]
    q2 = data[:, 1]
    w = data[:, 2]

    # Map bin centers back to indices
    ii = np.rint((xb - (xB_min + dxB / 2.0)) / dxB).astype(int)
    jj = np.rint((q2 - (Q2_min + dQ2 / 2.0)) / dQ2).astype(int)
    ii = np.clip(ii, 0, xB_bins - 1)
    jj = np.clip(jj, 0, Q2_bins - 1)
    for x, y, ww in zip(ii, jj, w):
        heatmap[y, x] += ww

    return xb_centers, q2_centers, heatmap, (xB_min, xB_max, Q2_min, Q2_max), target_info
